module cascaded_encoder (
    input       [31:0] input_signal,   // 32-bit input signal to be encoded
    output reg  [4:0] out,            // 5-bit output representing the index of the highest-priority active input
    output reg  [3:0] out_upper_half, // 4-bit output representing the index of the highest-priority active input in the upper half
    output reg  [3:0] out_lower_half  // 4-bit output representing the index of the highest-priority active input in the lower half
);

parameter N = 32;
parameter M = 5;

// Define half-widths
parameter N_HALF = N / 2;
parameter M_HALF = M - 1;

// Create two instances of priority_encoder for upper and lower halves
priority_encoder #(
    .N(N_HALF),
    .M(M_HALF)
) encoder_upper (
    .input_signal(input_signal[N_HALF-1:0]),
    .out(out_upper_half)
);

priority_encoder #(
    .N(N_HALF),
    .M(M_HALF)
) encoder_lower (
    .input_signal(input_signal[N-1:N_HALF]),
    .out(out_lower_half)
);

// Determine which half has the highest priority input
// If upper half has an active input, use its index; otherwise, use lower half
// The MSB of the input has highest priority, so we check the upper half first

always @(*) begin
    // Check if any bit in the upper half is active
    logic [N_HALF-1:0] upper_bits = input_signal[N_HALF-1:0];
    logic [N_HALF-1:0] lower_bits = input_signal[N-1:N_HALF];

    // Determine if upper half has any active input
    logic upper_active = (upper_bits != 0);
    logic lower_active = (lower_bits != 0);

    if (upper_active) begin
        out = {1'b1, out_upper_half}; // MSB set to 1, rest from upper half
    end else if (lower_active) begin
        out = {1'b0, out_lower_half}; // MSB set to 0, rest from lower half
    end else begin
        out = 5'b00000; // No active inputs
    end
end

endmodule

// === priority_encoder module (to be placed in rtl/priority_encoder.v) ===
// This is the parameterized version of the original module.

module priority_encoder #(
    parameter int unsigned N,
    parameter int unsigned M
) (
    input       [N-1:0] input_signal,
    output reg  [M-1:0] out
);

generate
    if (N == 0) begin
        assign out = 0;
    end else begin
        always @(*) begin
            out = 0;
            for (int i = N-1; i >= 0; i = i - 1) begin
                if (input_signal[i])
                    out = {M-1{1'b0}, i};
            end
        end
    end
endgenerate

endmodule
