    input rst,

    input [3:0] data_in,
    input valid_in,
    output ready_out,
    output valid_out,
    output [3:0] data_out,
    input  ready_in    
    );

    reg [3:0] mem;
    reg data_present;
    reg ready_out_reg;
    reg valid_out_reg;

    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            mem <= 4'b0;
            data_present <= 0;
            valid_out_reg <= 0;
